const { ISLANDS_MANIFEST_FILE_PATH } = require('../../constants/manifest');
const { writeJsonFile, readJsonFile } = require('./json-file');
const { normalizeIslandClientName } = require('../normalizers');

/**
 * @typedef { object } Island
 * @property { string } name
 * @property { string } exportName
 * @property { string } path - Path to the island file
 * @property { boolean } namedExport - Indicates if the island should be imported as named export or default export
 *
 * @typedef { { [islandClient: string]: Island | undefined } } IslandsManifest
 *
 * @typedef {Object} ComponentFileInfo
 * @property {string} entry - Entry value of the island chunk
 * @property {string} exportKey - Key used to export the component (named or default)
 * @property {string} filePath - Path to the component file
 *
 */

/**
 * @returns { IslandsManifest | {} } Islands manifest content
 */
const readIslandsManifest = () => readJsonFile(ISLANDS_MANIFEST_FILE_PATH);

/**
 * @param { string } fullPath - full path of an island
 * @returns { Island } Island data (if exists)
 */
const getIslandByFullPath = (fullPath) => {
  const clientName = normalizeIslandClientName(fullPath);
  const islandsManifest = readIslandsManifest();

  return islandsManifest[clientName] || {};
};

/**
 * @param { IslandsManifest } clientIslands
 */
const writeIslandsManifest = (clientIslands) => {
  try {
    writeJsonFile(ISLANDS_MANIFEST_FILE_PATH, clientIslands);
  } catch (e) {
    throw new Error(
      `An error occurred while trying to write the Nordic Pages Islands manifest:\n${e.message}`,
    );
  }
};

module.exports = {
  writeIslandsManifest,
  readIslandsManifest,
  getIslandByFullPath,
};
